const input = $input.first().json || {};
const rawQuery = String(input.query || input.message || input.text || '').trim();
const normalized = rawQuery.toLowerCase();
const source = input._source || (rawQuery ? 'manual' : 'schedule');

function includesAny(text, patterns) {
  return patterns.some((pattern) => text.includes(pattern));
}

function extractQuantity(text, fallback = 0) {
  if (fallback > 0) return fallback;
  const match = text.match(/\b(\d{1,4})\b/);
  if (!match) return 0;
  const value = parseInt(match[1], 10);
  if (!Number.isFinite(value) || value < 1) return 0;
  return Math.min(value, 250);
}

function extractFilter(text, labels) {
  for (const label of labels) {
    const regex = new RegExp(`${label}\\s*[:=]?\\s*([\\wáéíóúñÁÉÍÓÚÑ-]+(?:\\s+[\\wáéíóúñÁÉÍÓÚÑ-]+){0,2})`, 'i');
    const match = text.match(regex);
    if (match) return match[1].trim();
  }
  return '';
}

