let ratingInsight = '', canMentionRating = false;
if (rating >= 4.8) { ratingInsight = 'Calificación excelente'; canMentionRating = true; } else if (rating >= 4.5) { ratingInsight = 'Muy buena calificación'; canMentionRating = true; } else if (rating >= 4.0) { ratingInsight = 'Buena calificación'; } else { ratingInsight = 'Calificación normal'; }
const rawWeb = (lead.website || '').trim();
const rawIg = (lead.instagram || '').trim();
