const city = isValidCity ? rawCity : '';
let bestAngle = 'general';
if (volumeLevel === 'very_high' || volumeLevel === 'high') bestAngle = 'volume';
else if (canMentionRating && rating >= 4.8) bestAngle = 'reputation';
