      let name = match[1].trim();
      name = name.replace(/^Dr\s/i,'Dr. ').replace(/^Dra\s/i,'Dra. ');
      const parts = name.split(/\s+/);
      if (parts.length >= 3 && parts[0].match(/^Dra?\.?$/i)) {
        extractedName = parts[0].replace(/^Dr$/i,'Dr.').replace(/^Dra$/i,'Dra.') + ' ' + parts[parts.length-1];
      } else {
