      duplicates.push({ ...group[i], motivo_descarte: 'duplicado_lead_id' });
    }
  }
}

if (duplicates.length === 0) {
  return [{ json: {
    _has_duplicates: false,
    _total_leads: all.length,
    _duplicates_found: 0
  }}];
}

// CRÍTICO: ordenar DESC para borrar de abajo hacia arriba sin desplazamiento
duplicates.sort((a,b) => b._row_number - a._row_number);

const summary = {
  _has_duplicates: true,
  _total_leads: all.length,
  _duplicates_found: duplicates.length
};

return duplicates.map(d => ({ json: { ...d, ...summary } }));

const total = $input.first().json._total_leads || 0;
const text = `✅ *Sin duplicados*\n\n📋 Total leads en la hoja: ${total}\n\nTodos los registros son únicos. No se movió nada.`;
return [{ json: { textResponse: text, toolResponse: `Sin duplicados. ${total} leads únicos.` } }];

const items  = $input.all();
const first  = items[0]?.json || {};
const total  = first._total_leads      || '?';
const found  = first._duplicates_found || items.length;
const kept   = (parseInt(total)||0) - (parseInt(found)||0);
const text   = `🧹 *Limpieza completada*\n\n` +
               `📋 Total leads procesados: ${total}\n` +
               `🔁 Duplicados encontrados: ${found}\n` +
               `✅ Leads únicos que quedan: ${kept}\n\n` +
               `Los duplicados fueron movidos a *leads_procesados* y borrados de *leads_master*.\n` +
               `La próxima ejecución de outreach solo verá leads únicos.`;
return [{ json: { textResponse: text, toolResponse: `${found} duplicados removidos. ${kept} leads únicos en leads_master.` }}];

const emailData = $input.first().json;
const recipient = String(emailData.email || emailData.send_to || '').trim().toLowerCase();
if (!recipient || !recipient.includes('@')) {
  throw new Error('Missing recipient email for Gmail duplicate check.');
}
const query = `in:sent to:${recipient}`;
return [{ json: { ...emailData, gmail_duplicate_query: query, recipient_email_normalized: recipient } }];

const source = $('🔎 Build Gmail Sent Query').first().json;
const matches = $input.all().map(item => item.json || {}).filter(item => item.id);
const first = matches[0] || {};
return [{ json: { ...source, _gmail_duplicate_found: matches.length > 0, _gmail_duplicate_count: matches.length, _gmail_duplicate_first_id: first.id || '', _gmail_duplicate_first_subject: first.subject || '', _gmail_duplicate_first_date: first.internalDate || first.date || '' } }];

const lead = $input.first().json || {};
const now = new Date().toISOString();
const lastSent = lead._gmail_last_sent_at || now;
return [{ json: {
  ...lead,
  action_type: lead.action_type || 'send_email_skipped',
  delivery_status: 'skipped_duplicate_gmail',
  contacted_at: lastSent,
  sent_timestamp: lastSent,
  gmail_id: lead._gmail_first_match_id || null,
  next_followup_date: '',
  _skip: true,
  _motivo: `duplicate_gmail_sent:${lead._gmail_duplicate_count || 1}`,
} }];
